// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	results := make([]UserActivitySummary, 0)

	if len(usernames) == 0 {
		return results, nil
	}

	// Build placeholders for the IN clause
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, len(usernames)+2) // +2 for startDate and endDate
	for i, username := range usernames {
		placeholders[i] = "?"
		args[i] = username
	}
	args[len(usernames)] = startDate
	args[len(usernames)+1] = endDate

	// Build the base SQL query
	sql := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, 
		       COUNT(*) as total, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?`, strings.Join(placeholders, ","))

	// Add action type filter if provided
	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	// Add grouping
	sql += " GROUP BY u.display_name, a.action_type"

	// Execute the raw query
	var maps []orm.Params
	_, err := o.Raw(sql, args...).Values(&maps)
	if err != nil {
		return nil, err
	}

	// Map results to UserActivitySummary structs
	for _, m := range maps {
		summary := UserActivitySummary{}

		// Handle display_name
		if dn, ok := m["display_name"].(string); ok {
			summary.DisplayName = dn
		}

		// Handle action_type
		if at, ok := m["action_type"].(string); ok {
			summary.ActionType = at
		}

		// Handle total_actions (count)
		if total, ok := m["total"]; ok {
			switch v := total.(type) {
			case int64:
				summary.TotalActions = int(v)
			case int:
				summary.TotalActions = v
			case string:
				fmt.Sscanf(v, "%d", &summary.TotalActions)
			}
		}

		// Handle success_count
		if success, ok := m["success_count"]; ok {
			switch v := success.(type) {
			case int64:
				summary.SuccessCount = int(v)
			case int:
				summary.SuccessCount = v
			case string:
				fmt.Sscanf(v, "%d", &summary.SuccessCount)
			}
		}

		// Handle avg_duration
		if avg, ok := m["avg_duration"]; ok {
			switch v := avg.(type) {
			case float64:
				summary.AvgDuration = v
			case string:
				fmt.Sscanf(v, "%f", &summary.AvgDuration)
			case int64:
				summary.AvgDuration = float64(v)
			case int:
				summary.AvgDuration = float64(v)
			}
		}

		results = append(results, summary)
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	results := make([]map[string]interface{}, 0)

	if len(departments) == 0 {
		return results, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":    true,
		"role":          true,
		"display_name":  true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build placeholders for the IN clause
	placeholders := make([]string, len(departments))
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		placeholders[i] = "?"
		args[i] = dept
	}

	// Build the SQL query
	// We need to join user_profile and user_activity to get user_count and total_activities
	sql := fmt.Sprintf(`
		SELECT u.%s as group_value, 
		       COUNT(DISTINCT u.id) as user_count, 
		       COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s`, groupByField, strings.Join(placeholders, ","), groupByField)

	// Execute the raw query
	var maps []orm.Params
	_, err := o.Raw(sql, args...).Values(&maps)
	if err != nil {
		return nil, err
	}

	// Convert orm.Params to []map[string]interface{}
	for _, m := range maps {
		newMap := make(map[string]interface{})
		for k, v := range m {
			newMap[k] = v
		}
		results = append(results, newMap)
	}

	return results, nil
}

