	UserCount       int64  `orm:"column(user_count)"`
	TotalActivities int64  `orm:"column(total_activities)"`
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	// Handle empty usernames slice to avoid SQL syntax errors
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Prepare placeholders for the IN clause
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, len(usernames)+2) // +2 for startDate and endDate
	for i, username := range usernames {
		placeholders[i] = "?"
		args[i] = username
	}
	args[len(usernames)] = startDate
	args[len(usernames)+1] = endDate

	// Base SQL query
	query := `
		SELECT u.display_name, a.action_type, COUNT(*) as total, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (` + strings.Join(placeholders, ",") + `) 
		  AND a.created_at BETWEEN ? AND ?`

	// Add action type filter if provided
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	// Execute raw query
	var summaries []UserActivitySummary
	_, err := o.Raw(query, args).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	validFields := map[string]bool{
		"department":    true,
		"role":          true,
		"display_name":  true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Handle empty departments slice
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Prepare placeholders for the IN clause
	placeholders := make([]string, len(departments))
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		placeholders[i] = "?"
		args[i] = dept
	}

	// Build the query dynamically based on groupByField
	// We use a subquery to count users and activities per group
	query := fmt.Sprintf(`
		SELECT 
			u.%s as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COALESCE(SUM(act_count), 0) as total_activities
		FROM user_profile u
		LEFT JOIN (
			SELECT user_id, COUNT(*) as act_count
			FROM user_activity
			GROUP BY user_id
		) a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s
		ORDER BY group_value`, 
		groupByField, 
		strings.Join(placeholders, ","), 
		groupByField)

	// Execute raw query
	var results []DepartmentReport
	_, err := o.Raw(query, args).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	// Convert to []map[string]interface{} for compatibility
	var maps []map[string]interface{}
	for _, r := range results {
		maps = append(maps, map[string]interface{}{
			"group_value":      r.GroupValue,
			"user_count":       r.UserCount,
			"total_activities": r.TotalActivities,
		})
	}

	return maps, nil
}

